if (! function_exists('tool_composition_recommender')) {
    function tool_composition_recommender($all_tools, $edges, $max_suggestions = null)
    {
        if (!is_array($all_tools) || !is_array($edges)) {
            return json_encode(['error' => 'all_tools and edges must be arrays']);
        }
        $max = isset($max_suggestions) && $max_suggestions > 0 ? (int)$max_suggestions : 10;

        // Build adjacency and reverse-adjacency maps
        $outgoing = []; // source -> [targets]
        $incoming = []; // target -> [sources]
        foreach ($edges as $e) {
            $s = $e['source'] ?? '';
            $t = $e['target'] ?? '';
            if ($s && $t) {
                $outgoing[$s][] = $t;
                $incoming[$t][] = $s;
            }
        }

        $suggestions = [];

        // 1. Tools with no edges at all (completely unused in compositions)
        $tools_with_edges = array_unique(array_merge(array_keys($outgoing), array_keys($incoming)));
        $unused = array_diff($all_tools, $tools_with_edges);
        // Filter out internal/administrative tools
        $skip = ['make_tool','suggest_system_prompt','list_directory','read_file','write_file',
                 'list_prompt_resources','read_prompt_resource','search_prompt_resources',
                 'notes_store','notes_get','notes_list'];
        $unused = array_values(array_diff($unused, $skip));
        if (!empty($unused)) {
            $suggestions[] = [
                'type' => 'unused_tool',
                'description' => 'Tool has never been used in any composition',
                'tools' => $unused,
                'idea' => 'Try composing these tools with any other tool to discover new capabilities.',
            ];
        }

        // 2. Tools with only 1 connection (under-explored)
        $one_conn = [];
        foreach ($all_tools as $t) {
            $outCount = count($outgoing[$t] ?? []);
            $inCount = count($incoming[$t] ?? []);
            if ($outCount + $inCount === 1 && !in_array($t, $skip)) {
                $one_conn[] = $t;
            }
        }
        if (!empty($one_conn)) {
            $suggestions[] = [
                'type' => 'under_explored',
                'description' => 'Tools with only one composition connection',
                'tools' => $one_conn,
                'idea' => 'These tools have only been composed one way. Try connecting them to other tools in new ways.',
            ];
        }

        // 3. Transitive chain suggestions: if A->B and B->C exist, suggest A->C
        $transitive = [];
        foreach ($outgoing as $a => $bs) {
            foreach ($bs as $b) {
                if (isset($outgoing[$b])) {
                    foreach ($outgoing[$b] as $c) {
                        // Check if A->C already exists
                        $exists = false;
                        foreach ($edges as $e) {
                            if (($e['source'] ?? '') === $a && ($e['target'] ?? '') === $c) {
                                $exists = true;
                                break;
                            }
                        }
                        if (!$exists && $a !== $c && count($transitive) < $max) {
                            $transitive[] = [
                                'type' => 'transitive',
                                'description' => "{$a}→{$b}→{$c} : {$a} feeds {$b} which feeds {$c}",
                                'chain' => [$a, $b, $c],
                                'idea' => "Since {$a} composes with {$b}, and {$b} composes with {$c}, try composing {$a} directly with {$c}.",
                            ];
                        }
                    }
                }
            }
        }
        $suggestions = array_merge($suggestions, $transitive);

        // 4. Suggest reverse compositions: if A->B exists, suggest B->A (bidirectional)
        $reverse = [];
        foreach ($edges as $e) {
            $s = $e['source'] ?? '';
            $t = $e['target'] ?? '';
            if ($s && $t) {
                $exists = false;
                foreach ($edges as $e2) {
                    if (($e2['source'] ?? '') === $t && ($e2['target'] ?? '') === $s) {
                        $exists = true;
                        break;
                    }
                }
                if (!$exists && count($reverse) + count($suggestions) < $max + 5) {
                    $reverse[] = [
                        'type' => 'reverse_composition',
                        'description' => "Try composing {$t}→{$s} (reverse of existing {$s}→{$t})",
                        'idea' => "The reverse pipeline might produce interestingly different results.",
                    ];
                }
            }
        }
        $suggestions = array_merge($suggestions, $reverse);

        // 5. If a tool has many outputs and another has many inputs, suggest connecting them
        $hub_tools = array_keys($outgoing);
        $leaf_tools = array_keys($incoming);
        $cross = [];
        foreach ($hub_tools as $h) {
            foreach ($leaf_tools as $l) {
                if ($h === $l || in_array($l, $outgoing[$h] ?? [])) continue;
                if (count($cross) >= $max) break 2;
                $cross[] = [
                    'type' => 'hub_to_leaf',
                    'description' => "Compose output of {$h} into {$l}",
                    'idea' => "{$h} produces output that {$l} could process. Try the pipeline: {$h} → {$l}.",
                ];
            }
        }
        $suggestions = array_merge($suggestions, $cross);

        // Deduplicate and limit
        $seen = [];
        $unique = [];
        foreach ($suggestions as $s) {
            $key = json_encode($s);
            if (!isset($seen[$key])) {
                $seen[$key] = true;
                $unique[] = $s;
            }
        }

        return json_encode([
            'total_suggestions' => count($unique),
            'displayed' => min(count($unique), $max),
            'suggestions' => array_slice($unique, 0, $max),
            'stats' => [
                'total_tools' => count($all_tools),
                'tools_with_edges' => count($tools_with_edges),
                'unused_tools' => count($unused),
                'under_explored_tools' => count($one_conn),
                'transitive_chains_found' => count($transitive),
            ],
        ]);
    }
}
